settings.custom_liquid:
{% comment %}
  ============================================
  PRODUCT FEATURES GRID - CUSTOM LIQUID
  ============================================
  Código listo para pegar en la sección "Liquid Personalizado"

  INSTRUCCIONES:
  1. Ve a Theme Customizer
  2. Agrega la sección "Liquid Personalizado"
  3. Pega este código en el campo "Custom liquid"
  4. Ajusta padding y layout según necesites
{% endcomment %}

<style>
  .product-features-custom {
    background-color: #ffffff;
    border: 1px solid #e5e7eb;
    border-radius: 0.5rem;
    padding: 1rem;
    margin: 0 auto;
    max-width: 100%;
  }

  .product-features-grid-custom {
    display: grid;
    grid-template-columns: 1fr;
    gap: 0.75rem;
  }

  @media (min-width: 640px) {
    .product-features-grid-custom {
      grid-template-columns: repeat(2, 1fr);
    }
  }

  .feature-item-custom {
    display: flex;
    align-items: center;
    gap: 0.75rem;
  }

  .feature-icon-container-custom {
    width: 2.5rem;
    height: 2.5rem;
    background-color: #111827;
    border-radius: 0.5rem;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
  }

  .feature-icon-custom {
    width: 1.5rem;
    height: 1.5rem;
  }

  .feature-content-custom {
    flex: 1;
  }

  .feature-title-custom {
    color: #111827;
    font-size: 0.875rem;
    font-weight: 600;
    line-height: 1.25;
    margin-bottom: 0.125rem;
  }

  .feature-description-custom {
    color: #4b5563;
    font-size: 0.75rem;
    line-height: 1.5;
  }
</style>

