          <rect x="14" y="3" width="7" height="7" rx="1.5" fill="#ef4444" fill-opacity="0.2" stroke="#ef4444" stroke-width="1.5"/>
          <rect x="3" y="14" width="7" height="7" rx="1.5" fill="#ef4444" fill-opacity="0.2" stroke="#ef4444" stroke-width="1.5"/>
