      <div class="feature-icon-container-custom">
        <svg class="feature-icon-custom" viewBox="0 0 24 24" fill="none">
          <circle cx="12" cy="12" r="9" fill="#ef4444" fill-opacity="0.2" stroke="#ef4444" stroke-width="1.5"/>
          <path d="M12 3C12 3 8 7 8 12C8 17 12 21 12 21" stroke="#ef4444" stroke-width="1.5" stroke-linecap="round"/>
          <path d="M12 3C12 3 16 7 16 12C16 17 12 21 12 21" stroke="#ef4444" stroke-width="1.5" stroke-linecap="round"/>
