{% endcomment %}

<style>
  /* Reset y contenedor principal */
  .bfr-topbar-wrapper * {
    box-sizing: border-box !important;
    margin: 0 !important;
    padding: 0 !important;
  }

  .bfr-topbar {
    position: relative !important;
    margin-bottom: 1.5rem !important;
    overflow: hidden !important;
    border-radius: 0.75rem !important;
    height: 64px !important;
    width: 100% !important;
  }

  /* Animated mesh gradient background */
  .bfr-gradient-bg {
    position: absolute !important;
    top: 0 !important;
    right: 0 !important;
    bottom: 0 !important;
    left: 0 !important;
    background: linear-gradient(to right, #4f46e5, #9333ea, #ec4899) !important;
  }

  .bfr-gradient-overlay {
    position: absolute !important;
    top: 0 !important;
    right: 0 !important;
    bottom: 0 !important;
    left: 0 !important;
    background: linear-gradient(to right, #ec4899, #f43f5e, #f97316) !important;
    mix-blend-mode: multiply !important;
    animation: bfr-slide 8s linear infinite !important;
  }

  @keyframes bfr-slide {
    0% { transform: translateX(-100%); }
    100% { transform: translateX(100%); }
  }

  /* Noise texture overlay */
  .bfr-noise {
    position: absolute !important;
    top: 0 !important;
    right: 0 !important;
    bottom: 0 !important;
    left: 0 !important;
    background-color: rgba(0, 0, 0, 0.3) !important;
    backdrop-filter: blur(4px) !important;
    -webkit-backdrop-filter: blur(4px) !important;
  }

  /* Scanline effect */
  .bfr-scanline {
    position: absolute !important;
    top: 0 !important;
    right: 0 !important;
    bottom: 0 !important;
    left: 0 !important;
    height: 200% !important;
    background: linear-gradient(to bottom, transparent, rgba(255, 255, 255, 0.05), transparent) !important;
    animation: bfr-scanline 2s linear infinite !important;
  }

  @keyframes bfr-scanline {
    0% { transform: translateY(-100%); }
    100% { transform: translateY(100%); }
  }

  /* Glowing particles */
  .bfr-particle {
    position: absolute !important;
    border-radius: 50% !important;
    filter: blur(1px) !important;
    -webkit-filter: blur(1px) !important;
    pointer-events: none !important;
  }

  .bfr-particle-1 { width: 2px !important; height: 2px !important; background: #fbbf24 !important; left: 0% !important; top: 50% !important; animation: bfr-float-1 2s ease-in-out infinite !important; }
  .bfr-particle-2 { width: 3px !important; height: 3px !important; background: #f472b6 !important; left: 5% !important; top: 50% !important; animation: bfr-float-2 3s ease-in-out 0.1s infinite !important; }
  .bfr-particle-3 { width: 4px !important; height: 4px !important; background: #a78bfa !important; left: 10% !important; top: 50% !important; animation: bfr-float-3 4s ease-in-out 0.2s infinite !important; }
  .bfr-particle-4 { width: 2px !important; height: 2px !important; background: #fbbf24 !important; left: 15% !important; top: 50% !important; animation: bfr-float-1 2s ease-in-out 0.3s infinite !important; }
  .bfr-particle-5 { width: 3px !important; height: 3px !important; background: #f472b6 !important; left: 20% !important; top: 50% !important; animation: bfr-float-2 3s ease-in-out 0.4s infinite !important; }
  .bfr-particle-6 { width: 4px !important; height: 4px !important; background: #a78bfa !important; left: 25% !important; top: 50% !important; animation: bfr-float-3 4s ease-in-out 0.5s infinite !important; }
  .bfr-particle-7 { width: 2px !important; height: 2px !important; background: #fbbf24 !important; left: 30% !important; top: 50% !important; animation: bfr-float-1 2s ease-in-out 0.6s infinite !important; }
  .bfr-particle-8 { width: 3px !important; height: 3px !important; background: #f472b6 !important; left: 35% !important; top: 50% !important; animation: bfr-float-2 3s ease-in-out 0.7s infinite !important; }
  .bfr-particle-9 { width: 4px !important; height: 4px !important; background: #a78bfa !important; left: 40% !important; top: 50% !important; animation: bfr-float-3 4s ease-in-out 0.8s infinite !important; }
  .bfr-particle-10 { width: 2px !important; height: 2px !important; background: #fbbf24 !important; left: 45% !important; top: 50% !important; animation: bfr-float-1 2s ease-in-out 0.9s infinite !important; }
  .bfr-particle-11 { width: 3px !important; height: 3px !important; background: #f472b6 !important; left: 50% !important; top: 50% !important; animation: bfr-float-2 3s ease-in-out 1s infinite !important; }
  .bfr-particle-12 { width: 4px !important; height: 4px !important; background: #a78bfa !important; left: 55% !important; top: 50% !important; animation: bfr-float-3 4s ease-in-out 1.1s infinite !important; }
  .bfr-particle-13 { width: 2px !important; height: 2px !important; background: #fbbf24 !important; left: 60% !important; top: 50% !important; animation: bfr-float-1 2s ease-in-out 1.2s infinite !important; }
  .bfr-particle-14 { width: 3px !important; height: 3px !important; background: #f472b6 !important; left: 65% !important; top: 50% !important; animation: bfr-float-2 3s ease-in-out 1.3s infinite !important; }
  .bfr-particle-15 { width: 4px !important; height: 4px !important; background: #a78bfa !important; left: 70% !important; top: 50% !important; animation: bfr-float-3 4s ease-in-out 1.4s infinite !important; }
  .bfr-particle-16 { width: 2px !important; height: 2px !important; background: #fbbf24 !important; left: 75% !important; top: 50% !important; animation: bfr-float-1 2s ease-in-out 1.5s infinite !important; }
  .bfr-particle-17 { width: 3px !important; height: 3px !important; background: #f472b6 !important; left: 80% !important; top: 50% !important; animation: bfr-float-2 3s ease-in-out 1.6s infinite !important; }
  .bfr-particle-18 { width: 4px !important; height: 4px !important; background: #a78bfa !important; left: 85% !important; top: 50% !important; animation: bfr-float-3 4s ease-in-out 1.7s infinite !important; }
  .bfr-particle-19 { width: 2px !important; height: 2px !important; background: #fbbf24 !important; left: 90% !important; top: 50% !important; animation: bfr-float-1 2s ease-in-out 1.8s infinite !important; }
  .bfr-particle-20 { width: 3px !important; height: 3px !important; background: #f472b6 !important; left: 95% !important; top: 50% !important; animation: bfr-float-2 3s ease-in-out 1.9s infinite !important; }

  @keyframes bfr-float-1 {
    0%, 100% { transform: translateY(0) scale(1); opacity: 0.3; }
    50% { transform: translateY(-20px) scale(1.5); opacity: 1; }
  }
  @keyframes bfr-float-2 {
    0%, 100% { transform: translateY(0) scale(1); opacity: 0.3; }
    50% { transform: translateY(-20px) scale(1.5); opacity: 1; }
  }
  @keyframes bfr-float-3 {
    0%, 100% { transform: translateY(0) scale(1); opacity: 0.3; }
    50% { transform: translateY(-20px) scale(1.5); opacity: 1; }
  }

  /* Main content - EXACTO DE PRODUCT.TSX */
  .bfr-content {
    position: relative !important;
    z-index: 10 !important;
    height: 100% !important;
    display: flex !important;
    align-items: center !important;
    justify-content: space-between !important;
    padding: 0 0.75rem !important;
  }

  .bfr-left {
    display: flex !important;
    align-items: center !important;
    gap: 0.5rem !important;
  }

  .bfr-right {
    display: flex !important;
    align-items: center !important;
    gap: 0.375rem !important;
  }

  /* Lightning icon */
  .bfr-lightning-wrap {
    position: relative !important;
    flex-shrink: 0 !important;
    animation: bfr-wiggle 2s ease-in-out infinite !important;
  }

  @keyframes bfr-wiggle {
    0%, 100% { transform: rotate(0deg); }
    25% { transform: rotate(-5deg); }
    75% { transform: rotate(5deg); }
  }

  .bfr-lightning {
    width: 32px !important;
    height: 32px !important;
    border-radius: 0.5rem !important;
    background: linear-gradient(to bottom right, #fcd34d, #fb923c, #ef4444) !important;
    display: flex !important;
    align-items: center !important;
    justify-content: center !important;
    position: relative !important;
    animation: bfr-glow 1.5s ease-in-out infinite !important;
  }

  @keyframes bfr-glow {
    0%, 100% { box-shadow: 0 0 15px rgba(251, 191, 36, 0.6); }
    50% { box-shadow: 0 0 30px rgba(251, 191, 36, 0.9); }
  }

  .bfr-lightning svg {
    position: relative !important;
    z-index: 10 !important;
    width: 18px !important;
    height: 18px !important;
    color: white !important;
  }

  .bfr-lightning-inner {
    position: absolute !important;
    top: 0 !important;
    right: 0 !important;
    bottom: 0 !important;
    left: 0 !important;
    border-radius: 0.5rem !important;
    background: white !important;
    animation: bfr-pulse-inner 1.5s ease-in-out infinite !important;
  }

  @keyframes bfr-pulse-inner {
    0%, 100% { opacity: 0; }
    50% { opacity: 0.3; }
  }

  .bfr-pulse-ring {
    position: absolute !important;
    top: 0 !important;
    right: 0 !important;
    bottom: 0 !important;
    left: 0 !important;
    border-radius: 0.5rem !important;
    border: 2px solid #fbbf24 !important;
    animation: bfr-pulse-ring 1.5s ease-in-out infinite !important;
  }

  @keyframes bfr-pulse-ring {
    0% { transform: scale(1); opacity: 0.6; }
    100% { transform: scale(1.4); opacity: 0; }
  }

  /* Text area - gap-1 sm:gap-2 del original */
  .bfr-text-area {
    display: flex !important;
    align-items: center !important;
    gap: 0.5rem !important;
  }

  .bfr-label {
    color: white !important;
    text-transform: uppercase !important;
    letter-spacing: 0.1em !important;
    font-weight: 800 !important;
    font-size: 10px !important;
