<script>
  // LIMPIAR TODO
  if (window.bfrCountdownInterval) {
    clearInterval(window.bfrCountdownInterval);
  }

  // Detener CUALQUIER intervalo que pueda estar corriendo
  for (let i = 1; i < 99999; i++) {
    window.clearInterval(i);
  }

  (function() {
    'use strict';

    // Target: 02/12/2025 23:59:59
    const targetDate = new Date('December 1, 2025 23:59:59').getTime();

    function updateCountdown() {
      const now = new Date().getTime();
      const distance = targetDate - now;

      if (distance < 0) {
        document.getElementById('bfr-days').textContent = '00';
        document.getElementById('bfr-hours').textContent = '00';
        document.getElementById('bfr-minutes').textContent = '00';
        document.getElementById('bfr-seconds').textContent = '00';
        return;
      }

      // FÓRMULA ESTÁNDAR DE COUNTDOWN
      const days = Math.floor(distance / (1000 * 60 * 60 * 24));
      const hours = Math.floor((distance / (1000 * 60 * 60)) % 24);
      const minutes = Math.floor((distance / (1000 * 60)) % 60);
      const seconds = Math.floor((distance / 1000) % 60);

      // Actualizar
      document.getElementById('bfr-days').textContent = String(days).padStart(2, '0');
      document.getElementById('bfr-hours').textContent = String(hours).padStart(2, '0');
      document.getElementById('bfr-minutes').textContent = String(minutes).padStart(2, '0');
      document.getElementById('bfr-seconds').textContent = String(seconds).padStart(2, '0');
    }

    updateCountdown();
    window.bfrCountdownInterval = setInterval(updateCountdown, 1000);
  })();
</script>
